#include <iostream>
using namespace std;

template <typename T>
T MyMax(T a, T b) {
    return (a > b) ? a : b;
}

int main() {
    cout << MyMax<int>(3, 7) << endl;
    cout << MyMax<double>(3.5, 2.1) << endl;
    return 0;
}

#include <iostream>
using namespace std;

template <class T>
class Pair {
    T first, second;
public:
    Pair(T a, T b) : first(a), second(b) {}
    T getFirst() { return first; }
};

int main() {
    Pair<int> p(10, 20);
    cout << p.getFirst() << endl;
    return 0;
}

template <class T1, class T2>
class Pair {
    T1 first;
    T2 second;
public:
    Pair(T1 a, T2 b) : first(a), second(b) {}
};

#include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> v = {1, 2, 3, 4, 5};
    v.pop_back(); // Remove last
    v.push_back(6); // Add new
    cout << "Size: " << v.size() << endl;
    return 0;
}

for (vector<int>::iterator it = v.begin(); it != v.end(); ++it) {
    cout << *it << " ";
}

